class Solution:
    def countLargestGroup(self, n: int) -> int:
        sums = {}
        for num in range(1, n+1):
            s = 0
            temp = num
            while temp > 0:
                s += temp % 10
                temp = temp // 10
            if s in sums:
                sums[s] += 1
            else:
                sums[s] = 1
        max_size = max(sums.values())
        count = 0
        for v in sums.values():
            if v == max_size:
                count +=1
        return count

